    public static int solveQuery(int start, int end, int[] arr) {
        Map<Integer, Integer> frequency = new HashMap<>();
        for (int i = start; i <= end; i++) {
            int key = arr[i];
            frequency.put(key, frequency.getOrDefault(key, 0) + 1);
