    public static int ceilSearch(int[] arr, int low, int high, int x) {
        // If x is less than or equal to the first element, return its index
        if (x <= arr[low]) {
            return low;
        }
        // If x is greater than the last element, there is no ceiling in the array
        if (x > arr[high]) {
            return -1;
        }
        int mid = (low + high) / 2;
        // If the element is present at mid, return mid
        if (arr[mid] == x) {
            return mid;
        }
        // If x is greater than arr[mid]
        else if (arr[mid] < x) {
            // Check if arr[mid+1] is the ceiling of x
            if (mid + 1 <= high && x <= arr[mid + 1]) {
                return mid + 1;
            } else {
                // Recursively search in the right half
                return ceilSearch(arr, mid + 1, high, x);
            }
        }
        // If x is less than arr[mid]
        else {
            // Check if arr[mid] is the ceiling of x
            if (mid - 1 >= low && x > arr[mid - 1]) {
                return mid;
            } else {
                // Recursively search in the left half
                return ceilSearch(arr, low, mid - 1, x);
            }
        }
    }

