    public static boolean areConsecutive(int[] arr, int n) {
        if (n < 1) {
            return false;
        }
        // Find the minimum and maximum element in the array
        int min = arr[0];
        int max = arr[0];
        for (int i = 1; i < n; i++) {
            if (arr[i] < min) {
                min = arr[i];
            }
            if (arr[i] > max) {
                max = arr[i];
            }
        }
        // Check if the range is exactly n
        if (max - min + 1 == n) {
            boolean[] visited = new boolean[n];
            for (int i = 0; i < n; i++) {
                // If the element is already visited, then there is a duplicate
                if (visited[arr[i] - min]) {
                    return false;
                }
                visited[arr[i] - min] = true;
            }
            return true;
        }
        return false;
    }

