    public static int isPossible(int n, int index, int modulo, int M, int[] arr, int[][] dp) {
        // normalize modulo so that it's always non-negative
        modulo = ((modulo % M) + M) % M;
        // when we've processed all elements, check if modulo is 0
        if (index == n) {
            return (modulo == 0) ? 1 : 0;
        }
        // if this sub-problem has been computed before, return its value
        if (dp[index][modulo] != -1) {
            return dp[index][modulo];
        }
        // try adding current array value
        int placeAdd = isPossible(n, index + 1, modulo + arr[index], M, arr, dp);
        // try subtracting current array value
        int placeMinus = isPossible(n, index + 1, modulo - arr[index], M, arr, dp);
        // if either possibility returns true (represented as 1), then result is true (1), else false (0)
        int res = (placeAdd == 1 || placeMinus == 1) ? 1 : 0;
        dp[index][modulo] = res;
        return res;
    }

