    public static String constructPalin(String s, int len) {
        // Convert the string into a character array.
        char[] chars = s.toCharArray();
        int i = -1;
        int j = len;
        // Process characters from both ends towards the center.
        while (i < j) {
            i++;
            j--;
            if (chars[i] == chars[j] && chars[i] != '*') {
                // Characters match and are not wildcards, continue.
                continue;
            } else if (chars[i] == chars[j] && chars[i] == '*') {
                // Both are wildcards, assign them the default character 'a'.
                chars[i] = 'a';
                chars[j] = 'a';
                continue;
            } else if (chars[i] == '*') {
                // Replace the wildcard at the left with the corresponding right character.
                chars[i] = chars[j];
                continue;
            } else if (chars[j] == '*') {
                // Replace the wildcard at the right with the corresponding left character.
                chars[j] = chars[i];
                continue;
            }
            // If none of the conditions match, it's not possible to form a palindrome.
            System.out.println("Not Possible");
            return "";
        }
        return new String(chars);
    }

