    public static String decimalToBinary(double num, int k_prec) {
        String binary = "";
        int integral = (int) num;
        double fractional = num - integral;
        // Convert the integral part to binary
        while (integral > 0) {
            int rem = integral % 2;
            binary += rem; // Append the remainder as a character
            integral /= 2;
        }
        // Since the remainders are in reverse order, reverse the string
        binary = new StringBuilder(binary).reverse().toString();
        // Add the decimal point
        binary += '.';
        // Convert the fractional part to binary digits with k_prec precision
        while (k_prec > 0) {
            fractional *= 2;
            int fract_bit = (int) fractional;
            if (fract_bit == 1) {
                fractional -= fract_bit;
                binary += '1';
            } else {
                binary += '0';
            }
            k_prec--;
        }
        return binary;
    }

