    public static int minRemove(int[] arr, int n) {
        int[] lis = new int[n]; // Array to store the LIS values for each index
        int maxLength = 0;      // Variable to store the maximum length found
        // Initialize all elements of lis to 1
        for (int i = 0; i < n; i++) {
