    public static int numOfIncSubseqOfSizeK(int[] arr, int n, int k) {
        // Create a 2D dp array, where dp[l][i] stores the count of increasing subsequences
        // of size (l+1) ending at index i.
        int[][] dp = new int[k][n];
        // Base case: each element is an increasing sequence of length 1.
        for (int i = 0; i < n; i++) {
            dp[0][i] = 1;
        }
        // Build the DP table for subsequences of length 2 to k.
        for (int l = 1; l < k; l++) {
            for (int i = l; i < n; i++) {
                dp[l][i] = 0;
                // Check for all previous indices to extend the subsequence.
                for (int j = l - 1; j < i; j++) {
                    if (arr[j] < arr[i]) {
                        dp[l][i] += dp[l - 1][j];
                    }
                }
            }
        }
        // Sum up all counts of increasing subsequences of size k.
        int sum = 0;
        for (int i = k - 1; i < n; i++) {
            sum += dp[k - 1][i];
        }
        return sum;
    }

