    public static int possibleStrings(int n, int r, int b, int g) {
        // Create an array to store "factorial" values (actually triangular numbers)
        int[] fact = new int[n + 1];
        fact[0] = 1;
        for (int i = 1; i <= n; i++) {
            fact[i] = fact[i - 1] + i;
        }
        int left = n - (r + g + b);
        int sum = 0;
        for (int i = 0; i <= left; i++) {
            for (int j = 0; j <= left - i; j++) {
                int k = left - (i + j);
                // Calculate the denominator
                int denominator = fact[i + r] + fact[j + b] + fact[k + g];
                // Perform division and add the integer part of the result to sum.
                // In Python the division is done in floating points and then converted to int,
                // which truncates the fractional part. Here we use integer division.
                sum += fact[n] / denominator;
            }
        }
        return sum;
    }

