    public static long countP(int n, int k) {
        // Create a dp table with (n+1) rows and (k+1) columns.
        long[][] dp = new long[n + 1][k + 1];
        // Initialization is not strictly necessary since Java arrays default to 0,
        // but we show the logic:
        // For every i from 0 to n: dp[i][0] = 0
        for (int i = 0; i <= n; i++) {
            dp[i][0] = 0;
        }
        // For every j from 0 to k: dp[0][j] = 0
        for (int j = 0; j <= k; j++) {
            dp[0][j] = 0;
        }
        // Fill the dp table using the recurrence relation.
        // We start filling from 1 because the base case (when i==0 or j==0) is already set.
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= k; j++) {
                if (j == 1 || i == j) {
                    dp[i][j] = 1;
                } else {
                    dp[i][j] = j * dp[i - 1][j] + dp[i - 1][j - 1];
                }
            }
        }
        return dp[n][k];
    }

