        for (int gap = 2; gap < n; gap++) {
            for (int i = 0; i < n - gap; i++) {
                int j = gap + i;
                // If the current characters match and the interior substring is a palindrome
                if (s.charAt(i) == s.charAt(j) && P[i + 1][j - 1]) {
                    P[i][j] = true;
