    public static boolean isDivisibleBy12(String num) {
        if (num.length() >= 3) {
            // Get the last digit as integer
            int d1 = Character.getNumericValue(num.charAt(num.length() - 1));
            // The number is not divisible by 12 if the last digit (ones place) is odd
            if (d1 % 2 != 0) {
                return false;
            }
            // Get the second last digit
            int d2 = Character.getNumericValue(num.charAt(num.length() - 2));
            // Calculate the sum of digits
            int sum = 0;
            for (int i = 0; i < num.length(); i++) {
                sum += Character.getNumericValue(num.charAt(i));
            }
            // Check both divisibility conditions: by 3 and the last two digits form a number divisible by 4
            return (sum % 3 == 0 && ((d2 * 10 + d1) % 4 == 0));
        } else {
            // If the string representation of the number has less than 3 digits, convert it to an integer
            int number = Integer.parseInt(num);
            return (number % 12 == 0);
        }
    }

