    public static int eggDrop(int n, int k) {
        int[][] eggFloor = new int[n + 1][k + 1];
        // Initialize base cases:
        // With 0 floor, trials are 0; with 1 floor, trials are 1.
        for (int i = 1; i <= n; i++) {
            eggFloor[i][0] = 0;
            eggFloor[i][1] = 1;
        }
        // With one egg, trials are equal to the number of floors.
        for (int j = 1; j <= k; j++) {
            eggFloor[1][j] = j;
        }
        // Fill the rest of the table in a bottom-up manner.
        for (int i = 2; i <= n; i++) {
            for (int j = 2; j <= k; j++) {
                eggFloor[i][j] = Integer.MAX_VALUE;
                // Consider all possible floors to drop the egg from
                for (int x = 1; x <= j; x++) {
                    int res = 1 + Math.max(eggFloor[i - 1][x - 1], eggFloor[i][j - x]);
                    if (res < eggFloor[i][j]) {
                        eggFloor[i][j] = res;
                    }
                }
            }
        }
        return eggFloor[n][k];
