    public static int minPalPartion(String str) {
        int n = str.length();
        int[][] C = new int[n][n];
        boolean[][] P = new boolean[n][n];
        // Every single character is a palindrome
        for (int i = 0; i < n; i++) {
            P[i][i] = true;
            C[i][i] = 0;
        }
        // L is the length of substring
        for (int L = 2; L <= n; L++) {
            for (int i = 0; i <= n - L; i++) {
                int j = i + L - 1;
                // Check if substring from index i to j is a palindrome
                if (L == 2) {
                    P[i][j] = (str.charAt(i) == str.charAt(j));
                } else {
                    P[i][j] = (str.charAt(i) == str.charAt(j)) && P[i + 1][j - 1];
                }
                // If it's a palindrome, no need to partition further
                if (P[i][j]) {
                    C[i][j] = 0;
                } else {
                    // Initialize with a high value
                    C[i][j] = 100000000;
                    // Try cutting at every possible k and use the minimum cuts required
                    for (int k = i; k < j; k++) {
                        C[i][j] = Math.min(C[i][j], C[i][k] + C[k + 1][j] + 1);
                    }
                }
            }
        }
