        // Create matrices T and F with dimensions n x n
        int[][] T = new int[n][n];
        int[][] F = new int[n][n];
        // Initialize the diagonal values for T and F based on symbols
        for (int i = 0; i < n; i++) {
            if (symb[i] == 'T') {
                T[i][i] = 1;
            } else {
                T[i][i] = 0;
            }
            if (symb[i] == 'F') {
                F[i][i] = 1;
            } else {
                F[i][i] = 0;
            }
        }
        // gap represents the chain length difference
        for (int gap = 1; gap < n; gap++) {
            // i goes from 0 to n-gap-1, with j = i+gap
            for (int i = 0; i < n - gap; i++) {
                int j = i + gap;
                T[i][j] = 0;
                F[i][j] = 0;
                // Partition the expression at every possible location
                for (int g = 0; g < gap; g++) {
                    int k = i + g;
                    int tik = T[i][k] + F[i][k];
                    int tkj = T[k + 1][j] + F[k + 1][j];
                    // Depending on the operator, calculate T[i][j] and F[i][j]
                    if (oper[k] == '&') {
                        T[i][j] += T[i][k] * T[k + 1][j];
                        F[i][j] += (tik * tkj - T[i][k] * T[k + 1][j]);
                    } else if (oper[k] == '|') {
                        F[i][j] += F[i][k] * F[k + 1][j];
                        T[i][j] += (tik * tkj - F[i][k] * F[k + 1][j]);
                    } else if (oper[k] == '^') {
                        T[i][j] += (F[i][k] * T[k + 1][j] + T[i][k] * F[k + 1][j]);
                        F[i][j] += (T[i][k] * T[k + 1][j] + F[i][k] * F[k + 1][j]);
                    }
                }
            }
        }
        return T[0][n - 1];
    }

