        // Create a 2D boolean array with dimensions (n+1) x (sum+1)
        boolean[][] subset = new boolean[n + 1][sum + 1];
        // For sum = 0, true for all i
        for (int i = 0; i <= n; i++) {
            subset[i][0] = true;
        }
        // For no elements and positive sum, false
        for (int j = 1; j <= sum; j++) {
            subset[0][j] = false;
        }
        // Fill the subset table in bottom up manner
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= sum; j++) {
