        int sum1 = 0, sum2 = 0, sum3 = 0;
        // Calculate the sum of all elements in each stack
        for (int i = 0; i < n1; i++) {
            sum1 += stack1[i];
        }
        for (int i = 0; i < n2; i++) {
            sum2 += stack2[i];
        }
        for (int i = 0; i < n3; i++) {
            sum3 += stack3[i];
        }
        // top pointers for each stack
        int top1 = 0, top2 = 0, top3 = 0;
        // Continue until one of the stacks is empty
        while (true) {
            // If any stack is empty, no further equal sum is possible
            if (top1 == n1 || top2 == n2 || top3 == n3) {
                return 0;
            }
            // If all sums are equal, return the sum
            if (sum1 == sum2 && sum2 == sum3) {
                return sum1;
            }
            // Remove the top element from the stack with the greatest sum
            if (sum1 >= sum2 && sum1 >= sum3) {
                sum1 -= stack1[top1];
                top1++;
            } else if (sum2 >= sum1 && sum2 >= sum3) {
                sum2 -= stack2[top2];
                top2++;
            } else if (sum3 >= sum1 && sum3 >= sum2) {
                sum3 -= stack3[top3];
                top3++;
