    public static int MinimumCost(int[] cost, int n, int W) {
        // Define a large value for infinity
        int INF = 1000000000;
        // Prepare lists for coin values and corresponding weights
        ArrayList<Integer> val = new ArrayList<>();
        ArrayList<Integer> wt = new ArrayList<>();
        int size = 0;
        for (int i = 0; i < n; i++) {
            if (cost[i] != -1) {
                val.add(cost[i]);
                wt.add(i + 1);
                size++;
            }
        }
        // Update n to the number of valid coins
        n = size;
        // Create the DP table:
        int[][] min_cost = new int[n + 1][W + 1];
        // Initialize the first row: With 0 coins, cost for any weight is INF.
        for (int j = 0; j <= W; j++) {
            min_cost[0][j] = INF;
        }
        // A total weight of 0 can always be achieved with cost 0.
        for (int i = 0; i <= n; i++) {
            min_cost[i][0] = 0;
        }
        // Fill the DP table
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= W; j++) {
                // If the weight of this coin is more than the current weight j,
                // we cannot include this coin.
                if (wt.get(i - 1) > j) {
                    min_cost[i][j] = min_cost[i - 1][j];
                } else {
                    // Either do not include the coin or include it (and add the coin's cost)
                    min_cost[i][j] = Math.min(
                        min_cost[i - 1][j], 
                        min_cost[i][j - wt.get(i - 1)] + val.get(i - 1)
                    );
                }
            }
        }
        return (min_cost[n][W] == INF) ? -1 : min_cost[n][W];
    }

