    public static double maxAverageOfPath(int[][] cost, int N) {
        // Create and initialize dp table with dimensions N x N (only indices 0..N-1 are used)
        int[][] dp = new int[N][N];
        dp[0][0] = cost[0][0];
        // Fill the first column of dp table
        for (int i = 1; i < N; i++) {
            dp[i][0] = dp[i - 1][0] + cost[i][0];
        }
        // Fill the first row of dp table
        for (int j = 1; j < N; j++) {
            dp[0][j] = dp[0][j - 1] + cost[0][j];
        }
        // Fill the rest of the dp table
        for (int i = 1; i < N; i++) {
            for (int j = 1; j < N; j++) {
                dp[i][j] = Math.max(dp[i - 1][j], dp[i][j - 1]) + cost[i][j];
            }
        }
        // Calculate the maximum average of the path and return the result
        return (double) dp[N - 1][N - 1] / (2 * N - 1);
    }

