    public static boolean isPrime(int p) {
        // Calculate Mersenne number: 2^p - 1
        BigInteger checkNumber = BigInteger.valueOf(2).pow(p).subtract(BigInteger.ONE);
        // Initialize nextval as 4 mod checkNumber
        BigInteger nextval = BigInteger.valueOf(4).mod(checkNumber);
        // Perform the Lucas-Lehmer iteration for (p - 2) times
        for (int i = 1; i < p - 1; i++) {
            nextval = nextval.multiply(nextval).subtract(BigInteger.valueOf(2)).mod(checkNumber);
        }
        // The number p (with Mersenne prime 2^p - 1) is prime if and only if nextval equals 0.
        return nextval.equals(BigInteger.ZERO);
    }

