    public static void antiSpiralTraversal(int m, int n, int[][] a) {
        int k = 0;
        int l = 0;
        Stack<Integer> stk = new Stack<>();
        // Traverse the matrix in spiral order and push elements into the stack.
        while (k <= m && l <= n) {
            // Traverse the top row from the remaining rows.
            for (int i = l; i <= n; i++) {
                stk.push(a[k][i]);
            }
            k++;
            // Traverse the rightmost column from the remaining columns.
            for (int i = k; i <= m; i++) {
                stk.push(a[i][n]);
            }
            n--;
            // Traverse the bottom row from the remaining rows if any.
            if (k <= m) {
                for (int i = n; i >= l; i--) {
                    stk.push(a[m][i]);
                }
                m--;
            }
            // Traverse the leftmost column from the remaining columns if any.
            if (l <= n) {
                for (int i = m; i >= k; i--) {
                    stk.push(a[i][l]);
                }
                l++;
            }
        }
        // Print the stored elements in reverse order (anticlockwise spiral order)
        while (!stk.isEmpty()) {
            System.out.print(stk.pop() + " ");
        }
    }

