    public static int findMaximum(int[] a, int n, int k) {
        HashMap<Integer, Integer> b = new HashMap<>();
        // Build the dictionary mapping x -> minimum d
        for (int i = 0; i < n; i++) {
            int x = a[i];
            int d = Math.min(1 + i, n - i);
            if (!b.containsKey(x)) {
                b.put(x, d);
            } else {
                b.put(x, Math.min(d, b.get(x)));
            }
        }
        int ans = Integer.MAX_VALUE;
        // Find the minimum maximum value of b[x] and b[k-x]
        for (int i = 0; i < n; i++) {
            int x = a[i];
            int target = k - x;
            if (x != target && b.containsKey(target)) {
                ans = Math.min(ans, Math.max(b.get(x), b.get(target)));
            }
        }
        return ans;
    }

