    public static void rearrange(int[] arr, int n) {
        int max_idx = n - 1;
        int min_idx = 0;
        // max_elem is greater than the maximum element in the array
        int max_elem = arr[n - 1] + 1;
        // Traverse through the array and store both old and new values at every index
        for (int i = 0; i < n; i++) {
            if (i % 2 == 0) {
                // At even indices, we use the maximum element from the remaining part of the array
                arr[i] += (arr[max_idx] % max_elem) * max_elem;
                max_idx--;
