    public static String simplify(String str) {
        int len = str.length();
        StringBuilder res = new StringBuilder();
        Stack<Integer> s = new Stack<>();
        s.push(0);  // initial sign is positive
        for (int i = 0; i < len; i++) {
            char current = str.charAt(i);
            if (current == '+') {
                if (s.peek() == 1) {
                    res.append('-');
                } else if (s.peek() == 0) {
                    res.append('+');
                }
            } else if (current == '-') {
                if (s.peek() == 1) {
                    res.append('+');
                } else if (s.peek() == 0) {
                    res.append('-');
                }
            } else if (current == '(' && i > 0) {
                char prev = str.charAt(i - 1);
                if (prev == '-') {
                    int x = (s.peek() == 1) ? 0 : 1;
                    s.push(x);
                } else if (prev == '+') {
                    s.push(s.peek());
                }
            } else if (current == ')') {
                s.pop();
            } else {
                res.append(current);
            }
        }
        return res.toString();
    }

