    public static int minRemovalsDP(int[] arr, int n) {
        int longest_start = -1;
        int longest_end = 0;
        for (int start = 0; start < n; start++) {
            int currentMin = Integer.MAX_VALUE;
            int currentMax = Integer.MIN_VALUE;
            for (int end = start; end < n; end++) {
                int val = arr[end];
                if (val < currentMin) {
                    currentMin = val;
                }
                if (val > currentMax) {
                    currentMax = val;
                }
                // Break if the condition is violated.
                if (2 * currentMin <= currentMax) {
                    break;
                }
                // Update the longest valid subarray.
                if (longest_start == -1 || (end - start > longest_end - longest_start)) {
                    longest_start = start;
                    longest_end = end;
                }
            }
        }
        if (longest_start == -1) {
            return n;
        }
        return n - (longest_end - longest_start + 1);
    }

