    public static int gcd(int a, int b) {
        if (a == 0) {
            return b;
        }
        if (b == 0) {
            return a;
        }
        int k = 0;
        // Remove all common factors of 2
        while (((a | b) & 1) == 0) {
            a >>= 1;
            b >>= 1;
            k++;
        }
        // Make sure a is odd
        while ((a & 1) == 0) {
            a >>= 1;
        }
        while (b != 0) {
            // Remove all factors of 2 in b — they are not common
            while ((b & 1) == 0) {
                b >>= 1;
            }
            // Ensure a <= b
            if (a > b) {
                int temp = a;
                a = b;
                b = temp;
            }
            b = b - a;
        }
        // Restore common factors of 2
        return a << k;
    }

