    public static int gcd(int a, int b) {
        if (a == b) {
            return a;
        }
        if (a == 0) {
            return b;
        }
        if (b == 0) {
            return a;
        }
        // If a is even
        if ((a & 1) == 0) {
            // If b is odd
            if ((b & 1) != 0) {
                return gcd(a >> 1, b);
            } else {
                // Both a and b are even
                return gcd(a >> 1, b >> 1) << 1;
            }
        }
        // At this point, a is odd.
        // If b is even
        if ((b & 1) == 0) {
            return gcd(a, b >> 1);
        }
        // Both a and b are odd.
        if (a > b) {
            return gcd((a - b) >> 1, b);
        }
        return gcd((b - a) >> 1, a);
    }

