static     public int countTransformation(String a, String b) {
        int n = a.length();
        int m = b.length();
        if (m == 0) {
            return 1;
        }
        // Allocate a 2D dp array with dimensions m x n.
        int[][] dp = new int[m][n];
        // Loop over each character in string b and appropriate positions in string a.
        for (int i = 0; i < m; i++) {
            // j starts from i to ensure that we have enough characters from a to match b up to i.
            for (int j = i; j < n; j++) {
                if (i == 0) {
                    if (j == 0) {
                        // For the very first character
                        dp[i][j] = (a.charAt(j) == b.charAt(i)) ? 1 : 0;
                    } else {
                        // Accumulate count if current character in a equals the first character in b.
                        if (a.charAt(j) == b.charAt(i)) {
                            dp[i][j] = dp[i][j - 1] + 1;
                        } else {
                            dp[i][j] = dp[i][j - 1];
                        }
                    }
                } else {
                    // For subsequences beyond the first character in b.
                    if (a.charAt(j) == b.charAt(i)) {
                        dp[i][j] = dp[i][j - 1] + dp[i - 1][j - 1];
                    } else {
                        dp[i][j] = dp[i][j - 1];
                    }
                }
            }
        }
        return dp[m - 1][n - 1];
    }

